import java.nio.file.*;import java.sql.*;import java.util.*;import java.util.regex.*;
public class MerchantBrowserRestore{
 record DbConfig(String url,String username,String password){}
 public static void main(String[]args)throws Exception{List<String> lines=Files.readAllLines(Path.of(".ai/tmp/merchant-browser-restore.dat"));long uid=Long.parseLong(lines.get(0));String pwd=lines.get(1);DbConfig cfg=readDbConfig();try(Connection c=DriverManager.getConnection(cfg.url(),cfg.username(),cfg.password())){c.setAutoCommit(false);long tenantId;try(PreparedStatement ps=c.prepareStatement("select tenant_id from sys_user where user_id=?")){ps.setLong(1,uid);try(ResultSet rs=ps.executeQuery()){if(!rs.next())throw new IllegalStateException("User missing");tenantId=rs.getLong(1);}}try(PreparedStatement ps=c.prepareStatement("update sys_user set password=? where user_id=?")){ps.setString(1,pwd);ps.setLong(2,uid);ps.executeUpdate();}try(PreparedStatement ps=c.prepareStatement("update merchant_profile set contact_first_name=?, contact_last_name=?, contact_name=?, office_phone=?, mobile_phone=?, state=?, city=?, address_line1=?, address_line2=?, postal_code=?, remark=? where tenant_id=?")){int i=1;ps.setString(i++,"Check");ps.setString(i++,"Owner");ps.setString(i++,"Check Owner");ps.setString(i++,"+1-212-555-0100");ps.setString(i++,"+1-646-555-0199");ps.setString(i++,"CA");ps.setString(i++,"Los Angeles");ps.setString(i++,"200 Runtime Rd");ps.setString(i++,"Floor 3");ps.setString(i++,"90001");ps.setString(i++,"Full /check validation");ps.setLong(i++,tenantId);ps.executeUpdate();}c.commit();System.out.println("BROWSER_RESTORE_OK");}}
 static DbConfig readDbConfig()throws Exception{String yml=Files.readString(Path.of("bocoo-admin/src/main/resources/application-dev.yml"));Matcher m=Pattern.compile("url:\\s*(jdbc:postgresql:[^\\r\\n]+).*?username:\\s*([^\\r\\n]+).*?password:\\s*([^\\r\\n]+)",Pattern.DOTALL).matcher(yml);if(!m.find())throw new IllegalStateException("DB config not found");return new DbConfig(m.group(1).trim(),m.group(2).trim(),m.group(3).trim());}
}